from collections import Counter
class Solution:
    def solve(self, nums: List[int], k: int) -> int:
        if k < 0: return 0
        count = Counter(nums)
        res = 0
        for x in count:
            if k > 0:
                if x + k in count: res += 1
            else:
                if count[x] > 1: res += 1
        return res

